contracts/OzcarEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title OzcarEscrow
 * @dev Secure escrow contract with Security Sentinel integration and Circuit Breaker.
 */
contract OzcarEscrow is AccessControl, Pausable {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant FUNDER_ROLE = keccak256("FUNDER_ROLE");

    IERC20 public paymentToken;

    enum State { AWAITING_DEPOSIT, AWAITING_DELIVERY, COMPLETE, DISPUTE, REFUNDED }

    struct Escrow {
        uint256 escrowId;
        address buyer;
        address seller;
        address nftContract;
        uint256 tokenId;
        uint256 price;
        State state;
        bool isFunded;
        bool isFrozen; 
    }

    uint256 public nextEscrowId;
    mapping(uint256 => Escrow) public escrows;

    event EscrowCreated(uint256 indexed escrowId, address buyer, address seller, uint256 tokenId, uint256 price);
    event Deposited(uint256 indexed escrowId, uint256 amount);
    event DeliveryConfirmed(uint256 indexed escrowId);
    event FundsReleased(uint256 indexed escrowId, address seller, uint256 amount);
    event DisputeRaised(uint256 indexed escrowId);
    event EscrowFrozen(uint256 indexed escrowId, string reason);
    event EscrowUnfrozen(uint256 indexed escrowId);

    constructor(address initialAdmin, address _paymentToken) {
        _grantRole(DEFAULT_ADMIN_ROLE, initialAdmin);
        _grantRole(ADMIN_ROLE, initialAdmin);
        paymentToken = IERC20(_paymentToken);
    }

    modifier onlyBuyer(uint256 _escrowId) {
        require(msg.sender == escrows[_escrowId].buyer, "Only buyer can call this");
        _;
    }

    modifier onlySeller(uint256 _escrowId) {
        require(msg.sender == escrows[_escrowId].seller, "Only seller can call this");
        _;
    }

    modifier inState(uint256 _escrowId, State _state) {
        require(escrows[_escrowId].state == _state, "Invalid state");
        _;
    }

    modifier notFrozen(uint256 _escrowId) {
        require(!escrows[_escrowId].isFrozen, "Escrow is frozen by security sentinel");
        _;
    }

    function createEscrow(
        address _nftContract,
        uint256 _tokenId,
        address _buyer,
        uint256 _price
    ) external whenNotPaused returns (uint256) {
        IERC721 nft = IERC721(_nftContract);
        require(nft.ownerOf(_tokenId) == msg.sender, "Seller must own the vehicle");

        uint256 escrowId = nextEscrowId++;
        escrows[escrowId] = Escrow({
            escrowId: escrowId,
            buyer: _buyer,
            seller: msg.sender,
            nftContract: _nftContract,
            tokenId: _tokenId,
            price: _price,
            state: State.AWAITING_DEPOSIT,
            isFunded: false,
            isFrozen: false
        });

        emit EscrowCreated(escrowId, _buyer, msg.sender, _tokenId, _price);
        return escrowId;
    }

    /**
     * @dev Deposit funds into escrow.
     */
    function deposit(uint256 _escrowId) external whenNotPaused inState(_escrowId, State.AWAITING_DEPOSIT) notFrozen(_escrowId) {
        Escrow storage escrow = escrows[_escrowId];
        
        if (!hasRole(FUNDER_ROLE, msg.sender)) {
            if (escrow.buyer != address(0)) {
                require(msg.sender == escrow.buyer, "Only buyer or funder can deposit");
            } else {
                escrow.buyer = msg.sender;
            }
        }

        require(paymentToken.transferFrom(msg.sender, address(this), escrow.price), "Payment failed");

        escrow.isFunded = true;
        escrow.state = State.AWAITING_DELIVERY;
        
        emit Deposited(_escrowId, escrow.price);
    }

    function confirmDelivery(uint256 _escrowId) 
        external 
        whenNotPaused
        onlyBuyer(_escrowId) 
        inState(_escrowId, State.AWAITING_DELIVERY) 
        notFrozen(_escrowId) 
    {
        Escrow storage escrow = escrows[_escrowId];
        
        escrow.state = State.COMPLETE;
        
        require(paymentToken.transfer(escrow.seller, escrow.price), "Token transfer failed");

        IERC721(escrow.nftContract).transferFrom(escrow.seller, escrow.buyer, escrow.tokenId);

        emit DeliveryConfirmed(_escrowId);
        emit FundsReleased(_escrowId, escrow.seller, escrow.price);
    }

    /**
     * @dev Security function to freeze an escrow.
     */
    function freezeEscrow(uint256 _escrowId, string calldata _reason) external onlyRole(ADMIN_ROLE) {
        escrows[_escrowId].isFrozen = true;
        emit EscrowFrozen(_escrowId, _reason);
    }

    /**
     * @dev Admin function to unfreeze an escrow.
     */
    function unfreezeEscrow(uint256 _escrowId) external onlyRole(ADMIN_ROLE) {
        escrows[_escrowId].isFrozen = false;
        emit EscrowUnfrozen(_escrowId);
    }

    /**
     * @dev Global Circuit Breaker: Pause all escrow operations.
     */
    function pause() external onlyRole(ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(ADMIN_ROLE) {
        _unpause();
    }

    function raiseDispute(uint256 _escrowId) external whenNotPaused inState(_escrowId, State.AWAITING_DELIVERY) notFrozen(_escrowId) {
        require(msg.sender == escrows[_escrowId].buyer || msg.sender == escrows[_escrowId].seller, "Only participants can dispute");
        escrows[_escrowId].state = State.DISPUTE;
        emit DisputeRaised(_escrowId);
    }

    function resolveDispute(uint256 _escrowId, bool refundBuyer) 
        external 
        whenNotPaused
        onlyRole(ADMIN_ROLE) 
        inState(_escrowId, State.DISPUTE) 
        notFrozen(_escrowId) 
    {
        Escrow storage escrow = escrows[_escrowId];
        
        if (refundBuyer) {
            escrow.state = State.REFUNDED;
            require(paymentToken.transfer(escrow.buyer, escrow.price), "Refund transfer failed");
        } else {
            escrow.state = State.COMPLETE;
            require(paymentToken.transfer(escrow.seller, escrow.price), "Seller transfer failed");
            IERC721(escrow.nftContract).transferFrom(escrow.seller, escrow.buyer, escrow.tokenId);
        }
    }
}

contracts/OzcarGovernance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title OzcarGovernance
 * @dev Community-driven governance with 3-tier jury system
 * @notice 70% car owners, 30% technicians participation model
 */
contract OzcarGovernance is Ownable {
    IERC20 public ozcToken;
    
    // Enums
    enum JuryTier { CITIZEN, EXPERT, GRAND_JURY }
    enum CaseType { 
        MAINTENANCE_VERIFICATION,
        SELLER_DISPUTE,
        INSURANCE_CLAIM,
        WARRANTY_DISPUTE,
        PRICE_MANIPULATION,
        VEHICLE_CONDITION_DISPUTE
    }
    enum CaseStatus { PENDING, VALIDATED, REJECTED, DISPUTED }
    
    // Structs
    struct Juror {
        address wallet;
        JuryTier tier;
        uint256 votingPower;
        uint256 accuracy;           // 0-100
        uint256 totalVotes;
        uint256 correctVotes;
        uint256 ownedVehicles;      // NFT count
        uint256 stakingAmount;
        bool isActive;
        uint256 joinedAt;
    }
    
    struct Case {
        bytes32 id;
        CaseType caseType;
        address submitter;
        string ipfsHash;            // Evidence on IPFS
        uint256 createdAt;
        uint256 deadline;
        CaseStatus status;
        bool finalized;
    }
    
    struct Vote {
        address juror;
        JuryTier tier;
        bool decision;              // true = Valid, false = Invalid
        uint256 votingPower;
        uint256 timestamp;
    }
    
    // State variables
    mapping(address => Juror) public jurors;
    mapping(bytes32 => Case) public cases;
    mapping(bytes32 => Vote[]) public caseVotes;
    mapping(bytes32 => mapping(address => bool)) public hasVoted;
    
    address[] public activeJurors;
    bytes32[] public activeCases;
    
    // Constants
    uint256 public constant CITIZEN_MIN_STAKE = 10 ether;
    uint256 public constant EXPERT_MIN_STAKE = 50 ether;
    uint256 public constant GRAND_JURY_MIN_STAKE = 100 ether;
    
    uint256 public constant CITIZEN_VOTING_POWER = 1;
    uint256 public constant EXPERT_VOTING_POWER = 3;
    uint256 public constant GRAND_JURY_VOTING_POWER = 5;
    
    uint256 public constant CASE_DURATION = 24 hours;
    uint256 public constant REWARD_POOL_PER_CASE = 1000 ether; // 1000 OZC per case
    
    // Target ratios (in percentage)
    uint256 public constant TARGET_CITIZEN_RATIO = 70;
    uint256 public constant TARGET_EXPERT_RATIO = 20;
    uint256 public constant TARGET_GRAND_JURY_RATIO = 10;
    
    // Events
    event JurorRegistered(address indexed juror, JuryTier tier);
    event JurorUpgraded(address indexed juror, JuryTier oldTier, JuryTier newTier);
    event CaseSubmitted(bytes32 indexed caseId, CaseType caseType, address indexed submitter);
    event Voted(bytes32 indexed caseId, address indexed juror, bool decision);
    event CaseFinalized(bytes32 indexed caseId, bool finalDecision, uint256 validVotes, uint256 invalidVotes);
    event RewardDistributed(address indexed juror, uint256 amount);
    event AccuracyUpdated(address indexed juror, uint256 newAccuracy);
    
    constructor(address initialOwner, address _ozcToken) Ownable(initialOwner) {
        ozcToken = IERC20(_ozcToken);
    }
    
    /**
     * @dev Register as a juror (Citizen tier by default)
     * @param _ownedVehicles Number of vehicles owned (NFT count)
     */
    function registerAsJuror(uint256 _ownedVehicles) external {
        require(!jurors[msg.sender].isActive, "Already registered");
        require(_ownedVehicles >= 1, "Must own at least 1 vehicle");
        
        // Stake minimum OZC
        require(
            ozcToken.transferFrom(msg.sender, address(this), CITIZEN_MIN_STAKE),
            "Stake transfer failed"
        );
        
        jurors[msg.sender] = Juror({
            wallet: msg.sender,
            tier: JuryTier.CITIZEN,
            votingPower: CITIZEN_VOTING_POWER,
            accuracy: 0,
            totalVotes: 0,
            correctVotes: 0,
            ownedVehicles: _ownedVehicles,
            stakingAmount: CITIZEN_MIN_STAKE,
            isActive: true,
            joinedAt: block.timestamp
        });
        
        activeJurors.push(msg.sender);
        
        emit JurorRegistered(msg.sender, JuryTier.CITIZEN);
    }
    
    /**
     * @dev Upgrade juror tier by staking more tokens
     */
    function upgradeTier(JuryTier _newTier) external {
        Juror storage juror = jurors[msg.sender];
        require(juror.isActive, "Not a juror");
        require(_newTier > juror.tier, "Can only upgrade");
        
        uint256 additionalStake = 0;
        uint256 newVotingPower = 0;
        
        if (_newTier == JuryTier.EXPERT) {
            require(juror.ownedVehicles >= 2 || juror.accuracy >= 85, "Not eligible for Expert");
            additionalStake = EXPERT_MIN_STAKE - juror.stakingAmount;
            newVotingPower = EXPERT_VOTING_POWER;
        } else if (_newTier == JuryTier.GRAND_JURY) {
            require(juror.ownedVehicles >= 3 || juror.accuracy >= 95, "Not eligible for Grand Jury");
            additionalStake = GRAND_JURY_MIN_STAKE - juror.stakingAmount;
            newVotingPower = GRAND_JURY_VOTING_POWER;
        }
        
        if (additionalStake > 0) {
            require(
                ozcToken.transferFrom(msg.sender, address(this), additionalStake),
                "Additional stake transfer failed"
            );
            juror.stakingAmount += additionalStake;
        }
        
        JuryTier oldTier = juror.tier;
        juror.tier = _newTier;
        juror.votingPower = newVotingPower;
        
        emit JurorUpgraded(msg.sender, oldTier, _newTier);
    }
    
    /**
     * @dev Submit a new case for jury review
     * @param _caseType Type of case
     * @param _ipfsHash IPFS hash containing evidence and details
     */
    function submitCase(
        CaseType _caseType,
        string memory _ipfsHash
    ) external returns (bytes32) {
        bytes32 caseId = keccak256(abi.encodePacked(
            msg.sender,
            block.timestamp,
            _ipfsHash
        ));
        
        cases[caseId] = Case({
            id: caseId,
            caseType: _caseType,
            submitter: msg.sender,
            ipfsHash: _ipfsHash,
            createdAt: block.timestamp,
            deadline: block.timestamp + CASE_DURATION,
            status: CaseStatus.PENDING,
            finalized: false
        });
        
        activeCases.push(caseId);
        
        emit CaseSubmitted(caseId, _caseType, msg.sender);
        return caseId;
    }
    
    /**
     * @dev Vote on a case
     * @param _caseId Case ID to vote on
     * @param _decision true = Valid, false = Invalid/Spam
     */
    function vote(bytes32 _caseId, bool _decision) external {
        require(jurors[msg.sender].isActive, "Not an active juror");
        require(!hasVoted[_caseId][msg.sender], "Already voted");
        require(cases[_caseId].status == CaseStatus.PENDING, "Case not pending");
        require(block.timestamp < cases[_caseId].deadline, "Voting ended");
        
        Juror memory juror = jurors[msg.sender];
        
        caseVotes[_caseId].push(Vote({
            juror: msg.sender,
            tier: juror.tier,
            decision: _decision,
            votingPower: juror.votingPower,
            timestamp: block.timestamp
        }));
        
        hasVoted[_caseId][msg.sender] = true;
        jurors[msg.sender].totalVotes++;
        
        emit Voted(_caseId, msg.sender, _decision);
    }
    
    /**
     * @dev Finalize a case and distribute rewards
     * @param _caseId Case ID to finalize
     */
    function finalizeCase(bytes32 _caseId) external {
        Case storage caseData = cases[_caseId];
        require(!caseData.finalized, "Already finalized");
        require(block.timestamp >= caseData.deadline, "Voting period not ended");
        
        Vote[] memory votes = caseVotes[_caseId];
        require(votes.length > 0, "No votes");
        
        // Calculate weighted votes
        uint256 validVotes = 0;
        uint256 invalidVotes = 0;
        
        for (uint i = 0; i < votes.length; i++) {
            if (votes[i].decision) {
                validVotes += votes[i].votingPower;
            } else {
                invalidVotes += votes[i].votingPower;
            }
        }
        
        // Determine final decision
        bool finalDecision = validVotes > invalidVotes;
        caseData.status = finalDecision ? CaseStatus.VALIDATED : CaseStatus.REJECTED;
        caseData.finalized = true;
        
        // Distribute rewards to correct voters
        _distributeRewards(_caseId, finalDecision, votes);
        
        emit CaseFinalized(_caseId, finalDecision, validVotes, invalidVotes);
    }
    
    /**
     * @dev Internal function to distribute rewards
     */
    function _distributeRewards(
        bytes32 _caseId,
        bool _correctDecision,
        Vote[] memory _votes
    ) internal {
        uint256 correctVotersCount = 0;
        
        // Count correct voters
        for (uint i = 0; i < _votes.length; i++) {
            if (_votes[i].decision == _correctDecision) {
                correctVotersCount++;
            }
        }
        
        if (correctVotersCount == 0) return;
        
        uint256 rewardPerVoter = REWARD_POOL_PER_CASE / correctVotersCount;
        
        // Distribute rewards and update accuracy
        for (uint i = 0; i < _votes.length; i++) {
            address jurorAddress = _votes[i].juror;
            
            if (_votes[i].decision == _correctDecision) {
                // Correct vote: give reward
                ozcToken.transfer(jurorAddress, rewardPerVoter);
                jurors[jurorAddress].correctVotes++;
                
                emit RewardDistributed(jurorAddress, rewardPerVoter);
            }
            
            // Update accuracy
            _updateAccuracy(jurorAddress);
        }
    }
    
    /**
     * @dev Update juror accuracy
     */
    function _updateAccuracy(address _juror) internal {
        Juror storage juror = jurors[_juror];
        
        if (juror.totalVotes > 0) {
            juror.accuracy = (juror.correctVotes * 100) / juror.totalVotes;
            emit AccuracyUpdated(_juror, juror.accuracy);
        }
    }
    
    /**
     * @dev Get pending cases
     */
    function getPendingCases() external view returns (bytes32[] memory) {
        uint256 pendingCount = 0;
        
        // Count pending cases
        for (uint i = 0; i < activeCases.length; i++) {
            if (cases[activeCases[i]].status == CaseStatus.PENDING) {
                pendingCount++;
            }
        }
        
        // Create result array
        bytes32[] memory pendingCases = new bytes32[](pendingCount);
        uint256 index = 0;
        
        for (uint i = 0; i < activeCases.length; i++) {
            if (cases[activeCases[i]].status == CaseStatus.PENDING) {
                pendingCases[index] = activeCases[i];
                index++;
            }
        }
        
        return pendingCases;
    }
    
    /**
     * @dev Get juror statistics
     */
    function getJurorStats(address _juror) external view returns (
        JuryTier tier,
        uint256 votingPower,
        uint256 accuracy,
        uint256 totalVotes,
        uint256 correctVotes
    ) {
        Juror memory juror = jurors[_juror];
        return (
            juror.tier,
            juror.votingPower,
            juror.accuracy,
            juror.totalVotes,
            juror.correctVotes
        );
    }
    
    /**
     * @dev Get votes for a case
     */
    function getCaseVotes(bytes32 _caseId) external view returns (Vote[] memory) {
        return caseVotes[_caseId];
    }
    
    /**
     * @dev Emergency withdraw (only owner)
     */
    function emergencyWithdraw(uint256 _amount) external onlyOwner {
        ozcToken.transfer(owner(), _amount);
    }
}

